CREATE TABLE t (id INT) PARTITION BY LIST (id) (PARTITION p0 VALUES IN (0));

CREATE TABLE t (id INT) PARTITION BY LIST (id) (PARTITION p0 VALUES IN (1, 2, 3), PARTITION p1 VALUES IN (4, 5, 6));

CREATE TABLE t (name VARCHAR(30)) PARTITION BY LIST (name) (PARTITION p0 VALUES IN ('a', 'b'), PARTITION p1 VALUES IN ('c'));

CREATE TABLE t (id INT) PARTITION BY RANGE (id) (PARTITION p0 VALUES LESS THAN (10), PARTITION p1 VALUES LESS THAN MAXVALUE);